functions._addActorIfNew:
function _addActorIfNew(address actor) internal {
    if (!_isActor[actor]) {
        _isActor[actor] = true;
        actors.push(actor);
        deal(address(stakingToken), actor, INITIAL_BALANCE);
        deal(address(rewardToken), actor, INITIAL_BALANCE);
    }
}

functions._selectActor:
function _selectActor(uint256 seed) internal returns (address) {
    if (actors.length == 0) {
        address newActor = makeAddr("actor0");
        _isActor[newActor] = true;
        actors.push(newActor);
        deal(address(stakingToken), newActor, INITIAL_BALANCE);
        deal(address(rewardToken), newActor, INITIAL_BALANCE);
    }
    uint256 idx = bound(seed, 0, actors.length - 1);
    return actors[idx];
}

functions.actorsLength:
function actorsLength() external view returns (uint256) {
    return actors.length;
}

functions.handler_addNewActor:
function handler_addNewActor(uint256 seed) external {
    address newActor = makeAddr(string(abi.encodePacked("actor_new", seed, block.timestamp)));
    if (!_isActor[newActor]) {
        _isActor[newActor] = true;
        actors.push(newActor);
        deal(address(stakingToken), newActor, INITIAL_BALANCE);
        deal(address(rewardToken), newActor, INITIAL_BALANCE);
    }
}

functions.handler_addRewards:
function handler_addRewards(uint256 seed, uint256 amount) external {
    address actor = _selectActor(seed);
    _addActorIfNew(actor);
    uint256 balance = rewardToken.balanceOf(actor);
    if (balance == 0) return;
    amount = bound(amount, 1, balance > type(uint128).max ? type(uint128).max : balance);
    vm.startPrank(actor);
    rewardToken.approve(address(staking), amount);
    staking.addRewards(amount);
    vm.stopPrank();
    ghost_rewards_added += amount;
}

functions.handler_claimRewards:
function handler_claimRewards(uint256 seed) external {
    address actor = _selectActor(seed);
    _addActorIfNew(actor);
    uint256 balanceBefore = rewardToken.balanceOf(actor);
    vm.startPrank(actor);
    staking.claimRewards();
    vm.stopPrank();
    uint256 balanceAfter = rewardToken.balanceOf(actor);
    uint256 actualClaimed = balanceAfter - balanceBefore;
    ghost_rewards_claimed += actualClaimed;
}

functions.handler_stake:
function handler_stake(uint256 seed, uint256 amount) external {
    address actor = _selectActor(seed);
    _addActorIfNew(actor);
    uint256 balance = stakingToken.balanceOf(actor);
    if (balance == 0) return;
    amount = bound(amount, 1, balance > type(uint128).max ? type(uint128).max : balance);
    vm.startPrank(actor);
    stakingToken.approve(address(staking), amount);
    staking.stake(amount);
    vm.stopPrank();
    ghost_staked[actor] += amount;
    ghost_total_staked += amount;
    ghost_staking_deposited[actor] += amount;
}

functions.handler_unstake:
function handler_unstake(uint256 seed, uint256 amount) external {
    address actor = _selectActor(seed);
    _addActorIfNew(actor);
    uint256 staked = staking.stakedOf(actor);
    if (staked == 0) return;
    amount = bound(amount, 1, staked);
    vm.startPrank(actor);
    staking.unstake(amount);
    vm.stopPrank();
    ghost_staked[actor] -= amount;
    ghost_total_staked -= amount;
    ghost_staking_withdrawn[actor] += amount;
}

invariants.invariant_earnedNeverExceedsAvailableRew:
function invariant_earnedNeverExceedsAvailableRewards() external view {
    uint256 totalEarned = 0;
    uint256 len = handler.actorsLength();
    for (uint256 i = 0; i < len; i++) {
        address actor = handler.actors(i);
        totalEarned += staking.earned(actor);
    }
    uint256 available = rewardToken.balanceOf(address(staking));
    assertLe(
        totalEarned,
        available,
        "sum of earned() > reward token balance in contract"
    );
}

invariants.invariant_ghostRewardClaimedNeverExceeds:
function invariant_ghostRewardClaimedNeverExceedsAdded() external view {
    assertLe(
        handler.ghost_rewards_claimed(),
        handler.ghost_rewards_added(),
        "ghost: actual tokens claimed > tokens added as rewards"
    );
}

invariants.invariant_ghostTotalStaked:
function invariant_ghostTotalStaked() external view {
    assertEq(
        staking.totalStaked(),
        handler.ghost_total_staked(),
        "totalStaked != ghost_total_staked"
    );
}

invariants.invariant_perActorStakingAccounting:
function invariant_perActorStakingAccounting() external view {
    uint256 len = handler.actorsLength();
    for (uint256 i = 0; i < len; i++) {
        address actor = handler.actors(i);
        uint256 deposited = handler.ghost_staking_deposited(actor);
        uint256 withdrawn = handler.ghost_staking_withdrawn(actor);
        assertEq(
            staking.stakedOf(actor),
            deposited - withdrawn,
            "stakedOf actor != deposited - withdrawn"
        );
    }
}

invariants.invariant_rewardClaimedNeverExceedsAdded:
function invariant_rewardClaimedNeverExceedsAdded() external view {
    assertLe(
        staking.totalRewardsClaimed(),
        staking.totalRewardsAdded(),
        "totalRewardsClaimed > totalRewardsAdded"
    );
}

invariants.invariant_rewardTokenSolvency:
function invariant_rewardTokenSolvency() external view {
    uint256 contractBalance = rewardToken.balanceOf(address(staking));
    uint256 added = handler.ghost_rewards_added();
    uint256 claimed = handler.ghost_rewards_claimed();
    assertGe(
        contractBalance,
        added - claimed,
        "reward token balance < (ghost_added - ghost_claimed)"
    );
}

invariants.invariant_stakingTokenBalance:
function invariant_stakingTokenBalance() external view {
    assertEq(
        stakingToken.balanceOf(address(staking)),
        staking.totalStaked(),
        "staking token balance != totalStaked"
    );
}

invariants.invariant_totalStakedConsistency:
function invariant_totalStakedConsistency() external view {
    uint256 sumStaked = 0;
    uint256 len = handler.actorsLength();
    for (uint256 i = 0; i < len; i++) {
        address actor = handler.actors(i);
        sumStaked += staking.stakedOf(actor);
    }
    assertEq(
        staking.totalStaked(),
        sumStaked,
        "totalStaked != sum of stakedOf actors"
    );
}

invariants.invariant_userRewardPerTokenPaidNeverExc:
function invariant_userRewardPerTokenPaidNeverExceedsStored() external view {
    uint256 stored = staking.rewardPerTokenStored();
    uint256 len = handler.actorsLength();
    for (uint256 i = 0; i < len; i++) {
        address actor = handler.actors(i);
        assertLe(
            staking.userRewardPerTokenPaid(actor),
            stored,
            "userRewardPerTokenPaid > rewardPerTokenStored"
        );
    }
}
